const items = $input.all();
const results = [];
const now = new Date();
const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

for (const item of items) {
  const clientId = item.json.id;

  // Find leads that need follow-up: stage < 3 and not updated in 24+ hours
  const leads = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/lead_interactions?client_id=eq.${clientId}&stage=lt.3&updated_at=lt.${twentyFourHoursAgo.toISOString()}&select=id,client_id,lead_name,lead_email,stage,score,source`,
    headers: {
      'apikey': $env.SUPABASE_API_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`
    }
  });

  if (leads && leads.length > 0) {
    for (const lead of leads) {
      results.push({ json: lead });
    }
  }
}

if (results.length === 0) {
  results.push({ json: { _skip: true } });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  if (item.json._skip) continue;

  const leadId = item.json.id;
  const newStage = (item.json.stage || 0) + 1;

  // PATCH the lead to advance follow-up stage
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/lead_interactions?id=eq.${leadId}`,
    headers: {
      'apikey': $env.SUPABASE_API_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: {
      stage: newStage,
      updated_at: new Date().toISOString()
    }
  });

  results.push({
    json: {
      client_id: item.json.client_id,
      lead_id: leadId,
      lead_name: item.json.lead_name,
      previous_stage: item.json.stage,
      new_stage: newStage
    }
  });
}

if (results.length === 0) {
  results.push({ json: { _skip: true } });
}

return results;
